import java.util.*;

public class ZigzagTraversal {

    static class Node {
        int val; Node left, right;
        Node(int v) { val = v; }
    }

    public List<List<Integer>> zigzag(Node root) {
        List<List<Integer>> result = new ArrayList<>();
        if (root == null) return result;
        Queue<Node> queue = new LinkedList<>();
        queue.add(root);
        boolean leftToRight = true;

        while (!queue.isEmpty()) {
            int size = queue.size();
            int[] level = new int[size];
            // TODO: fill 'level' left-to-right if leftToRight==true, else right-to-left
            //       add children to queue for next level
            List<Integer> levelList = new ArrayList<>();
            for (int v : level) levelList.add(v);
            result.add(levelList);
            leftToRight = !leftToRight;
        }
        return result;
    }

    public static void main(String[] args) {
        Node root = new Node(3);
        root.left = new Node(9); root.right = new Node(20);
        root.right.left = new Node(15); root.right.right = new Node(7);
        ZigzagTraversal zt = new ZigzagTraversal();
        System.out.println(zt.zigzag(root));
    }
}
